import re

def parse_duration(s: str) -> int:
    """Parse duration string like '2h30m', '45m', '1h', '90s' and return total seconds."""
    matches = re.findall(r'(\d+)([hms])', s)
    if not matches or ''.join(f'{num}{unit}' for num, unit in matches) != s:
        raise ValueError('Invalid duration format')
    total = 0
    for num, unit in matches:
        value = int(num)
        if unit == 'h':
            total += value * 3600
        elif unit == 'm':
            total += value * 60
        else:
            total += value
    return total
